patch:
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
index 76020d2b1dbf..8cb92cf6cc2e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineCompares.cpp
@@ -7416,6 +7416,7 @@ Instruction *InstCombinerImpl::foldICmpCommutative(CmpPredicate Pred,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   bool Changed = false;
   const SimplifyQuery Q = SQ.getWithInstruction(&I);
@@ -7451,6 +7452,22 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
     }
   }

+  // Fold icmp eq/ne (trunc nuw X), (trunc nuw Y) -> icmp eq/ne X, Y.
+  // This is safe because nuw truncation only extracts the low bits,
+  // so equality of low bits is equivalent to equality of the full values.
+  // This must happen before canonicalizeICmpBool to prevent it from
+  // transforming to xor form.
+  if (I.isEquality()) {
+    auto *Trunc0 = dyn_cast<TruncInst>(Op0);
+    auto *Trunc1 = dyn_cast<TruncInst>(Op1);
+    if (Trunc0 && Trunc1 && Trunc0->hasNoUnsignedWrap() &&
+        Trunc1->hasNoUnsignedWrap() &&
+        Trunc0->getSrcTy() == Trunc1->getSrcTy()) {
+      return new ICmpInst(I.getPredicate(), Trunc0->getOperand(0),
+                          Trunc1->getOperand(0));
+    }
+  }
+
   if (Op0->getType()->isIntOrIntVectorTy(1))
     if (Instruction *Res = canonicalizeICmpBool(I, Builder))
       return Res;
@@ -7745,6 +7762,7 @@ Instruction *InstCombinerImpl::visitICmpInst(ICmpInst &I) {
   return Changed ? &I : nullptr;
 }

+
 /// Fold fcmp ([us]itofp x, cst) if possible.
 Instruction *InstCombinerImpl::foldFCmpIntToFPConst(FCmpInst &I,
                                                     Instruction *LHSI,

